// Make sends whatever shape the scenario was wired to send.
// Normalize to our canonical lead schema. Add new keys here as new
// Make scenarios come online so we never have to touch them again.
const b = $input.first().json.body || $input.first().json;
return [{ json: {
  email:         (b.email || b.lead_email || b.Email || '').toLowerCase(),
  contactName:   b.full_name || b.name || [b.first_name, b.last_name].filter(Boolean).join(' ') || null,
  company:       b.company || b.company_name || null,
  phone:         b.phone || b.phone_number || null,
  campaignName:  b.campaign_name || b.campaign || null,
  campaignId:    b.campaign_id || null,
  source:        b.source || b.scenario_id || 'make',
  scenarioId:    b.scenario_id || null,
  dateIntroduced: b.date_introduced || new Date().toISOString().slice(0,10),
  status:        'not_yet_closed'
}}];
